   public static class QuestionInfo {
      public final String question;
      public final Map<String, String> options;

      public QuestionInfo(String question, Map<String, String> options) {
         this.question = question;
         this.options = options;
      }

      public String getOptionContent(String letter) {
         return (String)this.options.getOrDefault(letter, letter);
      }
   }
